cy.fixture('levels').then(data => {
  let result = {};
  _homePage.default.searchCourse(data.searchTerm);
  // Loop through levels by visible text
  data.levels.forEach(level => {
    result[level] = [];
    _searchPage.default.openDifficultyFilter();
    _searchPage.default.selectDifficulty(level); //  pass text like "Beginner"
    _searchPage.default.openLanguageFilter();
    _searchPage.default.extractLanguagesForLevel(level, result);
  });
  cy.then(() => {
    Object.keys(result).forEach(level => {
      cy.log(`=== ${level} ===`);
      result[level].forEach(({
        language,
        count
      }) => {
        cy.log(`${language}: ${count}`);
      });
    });
  });
});

cy.fixture('enterprise').then(datasets => {
  datasets.forEach(form => {
    cy.on('uncaught:exception', () => false);
    _enterprisePage.default.openForm();
    _enterprisePage.default.fillForm(form);
    if (form.expectedError) {
      cy.get('#ValidMsgEmail', {
        timeout: 10000
      }).should('be.visible').then($msg => {
        cy.log(`Error for ${form.email}: ${$msg.text()}`);
        cy.screenshot(`invalid-email-${form.email}`);
        // expect($msg.text()).to.contain('Invalid')
      });
    } else {
      cy.get('#ValidMsgEmail').should('not.exist');
      cy.log(`Form submitted successfully for ${form.email}`);
      cy.screenshot(`valid-email-${form.email}`);
    }
  });
});
